// OpenCL translation of pgain kernel logic and helper functions (partial conversion as requested for OpenCL kernel)
// This code represents the kernel logic that was parallelized by OpenMP in the original source.
// The host-side logic for invoking this kernel and managing memory is assumed to be handled externally.

#pragma OPENCL EXTENSION cl_khr_fp64 : enable

// Point structure with weight, assign index, and cost
typedef struct {
    float weight;
    long assign;
    float cost;
} Point_Struct;

// Kernel to compute gain for opening a new center x
__kernel void pgain_kernel(
    __global Point_Struct* p,          // array of Points
    __global const float* coord,       // flattened coordinates array (num_points * dim)
    __global float* work_mem,          // work memory for reductions (stride * (num_centers+1))
    __global int* center_table,        // mapping from point index to center index
    __global char* switch_membership, // flags for points switching membership
    const int num_points,              // number of points
    const int dim,                    // dimension of points
    const long x,                     // candidate center index
    const int K                      // stride (number of centers + 2, aligned)
)
{
    int i = get_global_id(0);
    if (i >= num_points) return;

    // Compute distance squared between point i and candidate center x
    float dist_x = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[i * dim + d] - coord[x * dim + d];
        dist_x += diff * diff;
    }
    float x_cost = dist_x * p[i].weight;
    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        // Atomically add to work_mem at position pid*stride for cost_of_opening_x (reduction done on host)
        // Here accumulate cost difference locally per work_mem row (center_table index)
        // Using atomic adds for partial sums since multiple work-items may write same location
        // But original code accumulates cost_of_opening_x per thread, so here just mark switch_membership for host reduction
    } else {
        int assign = p[i].assign;
        // Accumulate lower bound differences
        // Atomic add to work_mem at (center_table[assign]) location
        atomic_add(&work_mem[center_table[assign]], current_cost - x_cost);
    }
}

// Note: The above kernel assumes work_mem is pre-initialized to zero and switch_membership to zero.
// The host code must handle the partial sums reductions, update is_center array, update assignments,
// and manage synchronization and memory transfers.

// Additional kernels and host-side code would be needed to fully replace the OpenMP parallel sections,
// including kernels for dist computations, pspeedy, pFL, and localSearch loops.

// This file provides the main kernel pgain_kernel necessary for the parallel gain computation in OpenCL.

